const express = require('express');
const crypto = require('crypto');
const app = express();

app.use(express.json());

// In-memory storage (use a real database in production)
const users = new Map();
const levelCompletions = new Map();

// Game configuration
const GAME_CONFIG = {
  levels: {
    1: { minTime: 10, maxTime: 300, maxScore: 1000, rewards: { coins: 100, gems: 5 } },
    2: { minTime: 15, maxTime: 400, maxScore: 1500, rewards: { coins: 150, gems: 7 } },
    3: { minTime: 20, maxTime: 500, maxScore: 2000, rewards: { coins: 200, gems: 10 } },
  },
  rateLimit: {
    maxCompletionsPerHour: 20,
    minTimeBetweenCompletions: 5000, // 5 seconds
  },
  anomalyThresholds: {
    perfectScoreStreak: 5,
    minTimeStreak: 3,
    suspiciousScoreRatio: 0.95,
  }
};

// Initialize user
function initUser(userId) {
  if (!users.has(userId)) {
    users.set(userId, {
      id: userId,
      coins: 0,
      gems: 0,
      completedLevels: new Set(),
      stats: {
        totalCompletions: 0,
        perfectScores: 0,
        minTimesAchieved: 0,
        lastCompletionTime: 0,
        recentCompletions: [],
        flaggedForReview: false,
        suspicionScore: 0,
      }
    });
    levelCompletions.set(userId, []);
  }
  return users.get(userId);
}

// Server-side validation and anti-cheat
function validateLevelCompletion(userId, levelId, score, time, moves, sessionData) {
  const user = users.get(userId);
  const level = GAME_CONFIG.levels[levelId];
  const completions = levelCompletions.get(userId);
  const now = Date.now();

  const validationResult = {
    valid: true,
    reasons: [],
    suspicionIncrease: 0,
    rewardMultiplier: 1.0
  };

  // Check if level exists
  if (!level) {
    validationResult.valid = false;
    validationResult.reasons.push('Invalid level');
    return validationResult;
  }

  // Rate limiting - completions per hour
  const recentCompletions = completions.filter(c => now - c.timestamp < 3600000);
  if (recentCompletions.length >= GAME_CONFIG.rateLimit.maxCompletionsPerHour) {
    validationResult.valid = false;
    validationResult.reasons.push('Rate limit exceeded');
    validationResult.suspicionIncrease += 20;
    return validationResult;
  }

  // Minimum time between completions
  if (user.stats.lastCompletionTime > 0) {
    const timeSinceLastCompletion = now - user.stats.lastCompletionTime;
    if (timeSinceLastCompletion < GAME_CONFIG.rateLimit.minTimeBetweenCompletions) {
      validationResult.valid = false;
      validationResult.reasons.push('Completions too rapid');
      validationResult.suspicionIncrease += 30;
      return validationResult;
    }
  }

  // Validate score range
  if (score < 0 || score > level.maxScore) {
    validationResult.valid = false;
    validationResult.reasons.push('Invalid score');
    validationResult.suspicionIncrease += 50;
    return validationResult;
  }

  // Validate time range
  if (time < level.minTime || time > level.maxTime) {
    validationResult.valid = false;
    validationResult.reasons.push('Invalid completion time');
    validationResult.suspicionIncrease += 50;
    return validationResult;
  }

  // Check for impossible score/time combinations
  const scoreRatio = score / level.maxScore;
  const timeRatio = (level.maxTime - time) / (level.maxTime - level.minTime);
  
  // If score is very high but time is very low, it's suspicious
  if (scoreRatio > 0.95 && time < level.minTime * 1.5) {
    validationResult.suspicionIncrease += 25;
    validationResult.reasons.push('Suspicious score/time ratio');
  }

  // Validate moves if provided
  if (moves !== undefined) {
    const expectedMinMoves = Math.ceil(level.maxScore / 100);
    if (moves < expectedMinMoves && score > level.maxScore * 0.8) {
      validationResult.suspicionIncrease += 20;
      validationResult.reasons.push('Suspicious move count');
    }
  }

  // Pattern detection - perfect score streak
  const recentPerfectScores = user.stats.recentCompletions
    .slice(-GAME_CONFIG.anomalyThresholds.perfectScoreStreak)
    .filter(c => c.score === GAME_CONFIG.levels[c.levelId]?.maxScore).length;
  
  if (score === level.maxScore) {
    if (recentPerfectScores >= GAME_CONFIG.anomalyThresholds.perfectScoreStreak - 1) {
      validationResult.suspicionIncrease += 15;
      validationResult.reasons.push('Unusual perfect score streak');
    }
  }

  // Pattern detection - minimum time streak
  const recentMinTimes = user.stats.recentCompletions
    .slice(-GAME_CONFIG.anomalyThresholds.minTimeStreak)
    .filter(c => {
      const lvl = GAME_CONFIG.levels[c.levelId];
      return lvl && c.time <= lvl.minTime * 1.1;
    }).length;
  
  if (time <= level.minTime * 1.1) {
    if (recentMinTimes >= GAME_CONFIG.anomalyThresholds.minTimeStreak - 1) {
      validationResult.suspicionIncrease += 20;
      validationResult.reasons.push('Unusual minimum time streak');
    }
  }

  // Session validation
  if (sessionData) {
    if (!sessionData.sessionId || !sessionData.startTime) {
      validationResult.suspicionIncrease += 10;
      validationResult.reasons.push('Missing session data');
    } else {
      const sessionDuration = now - sessionData.startTime;
      if (sessionDuration < time * 1000 * 0.8) {
        validationResult.valid = false;
        validationResult.reasons.push('Session duration mismatch');
        validationResult.suspicionIncrease += 40;
        return validationResult;
      }
    }
  }

  // Progressive level check - can't complete level 3 without completing level 1 and 2
  if (levelId > 1) {
    for (let i = 1; i < levelId; i++) {
      if (!user.completedLevels.has(i)) {
        validationResult.valid = false;
        validationResult.reasons.push('Previous levels not completed');
        validationResult.suspicionIncrease += 35;
        return validationResult;
      }
    }
  }

  // Reduce rewards if suspicious
  user.stats.suspicionScore += validationResult.suspicionIncrease;
  
  if (user.stats.suspicionScore > 50) {
    validationResult.rewardMultiplier = 0.5;
  }
  if (user.stats.suspicionScore > 100) {
    validationResult.rewardMultiplier = 0.1;
    user.stats.flaggedForReview = true;
  }
  if (user.stats.suspicionScore > 150) {
    validationResult.valid = false;
    validationResult.reasons.push('Account flagged for suspicious activity');
    return validationResult;
  }

  return validationResult;
}

// Generate server-side verification token
function generateVerificationToken(userId, levelId, timestamp) {
  const secret = process.env.GAME_SECRET || 'change-this-secret-in-production';
  const data = `${userId}:${levelId}:${timestamp}`;
  return crypto.createHmac('sha256', secret).update(data).digest('hex');
}

// Endpoint: Complete level
app.post('/api/levels/:levelId/complete', (req, res) => {
  const { userId, score, time, moves, sessionData, clientToken } = req.body;
  const levelId = parseInt(req.params.levelId);

  if (!userId) {
    return res.status(400).json({ error: 'User ID required' });
  }

  const user = initUser(userId);
  const timestamp = Date.now();

  // Verify client token if provided (additional layer)
  if (clientToken) {
    const expectedToken = generateVerificationToken(userId, levelId, Math.floor(timestamp / 60000) * 60000);
    const previousToken = generateVerificationToken(userId, levelId, Math.floor(timestamp / 60000 - 1) * 60000);
    
    if (clientToken !== expectedToken && clientToken !== previousToken) {
      user.stats.suspicionScore += 30;
    }
  }

  // Validate the completion
  const validation = validateLevelCompletion(userId, levelId, score, time, moves, sessionData);

  if (!validation.valid) {
    return res.status(400).json({
      success: false,
      error: 'Invalid level completion',
      reasons: validation.reasons
    });
  }

  // Record completion
  const completion = {
    levelId,
    score,
    time,
    moves,
    timestamp,
    suspicionIncrease: validation.suspicionIncrease
  };

  levelCompletions.get(userId).push(completion);
  user.stats.recentCompletions.push(completion);
  if (user.stats.recentCompletions.length > 10) {
    user.stats.recentCompletions.shift();
  }

  user.stats.totalCompletions++;
  user.stats.lastCompletionTime = timestamp;
  user.completedLevels.add(levelId);

  // Calculate rewards with multiplier
  const baseRewards = GAME_CONFIG.levels[levelId].rewards;
  const actualRewards = {
    coins: Math.floor(baseRewards.coins * validation.rewardMultiplier),
    gems: Math.floor(baseRewards.gems * validation.rewardMultiplier)
  };

  res.json({
    success: true,
    levelId,
    score,
    time,
    rewardsAvailable: actualRewards,
    completionId: `${userId}-${levelId}-${timestamp}`,
    warnings: validation.reasons.length > 0 ? validation.reasons : undefined
  });
});

// Endpoint: Claim rewards
app.post('/api/rewards/claim', (req, res) => {
  const { userId, completionId } = req.body;

  if (!userId || !completionId) {
    return res.status(400).json({ error: 'User ID and completion ID required' });
  }

  const user = users.get(userId);
  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  // Parse completion ID
  const [compUserId, levelId, timestamp] = completionId.split('-');
  
  if (compUserId !== userId) {
    user.stats.suspicionScore += 50;
    return res.status(400).json({ error: 'Invalid completion ID' });
  }

  const completions = levelCompletions.get(userId);
  const completion = completions.find(c => 
    c.levelId === parseInt(levelId) && 
    c.timestamp === parseInt(timestamp)
  );

  if (!completion) {
    return res.status(404).json({ error: 'Completion not found' });
  }

  if (completion.rewardsClaimed) {
    return res.status(400).json({ error: 'Rewards already claimed' });
  }

  // Check if too much time has passed (prevent replay attacks)
  const now = Date.now();
  if (now - completion.timestamp > 300000) { // 5 minutes
    return res.status(400).json({ error: 'Reward claim window expired' });
  }

  // Recalculate validation to prevent tampering
  const validation = validateLevelCompletion(
    userId, 
    completion.levelId, 
    completion.score, 
    completion.time, 
    completion.moves, 
    null
  );

  if (!validation.valid) {
    return res.status(400).json({ error: 'Completion no longer valid' });
  }

  const baseRewards = GAME_CONFIG.levels[completion.levelId].rewards;
  const actualRewards = {
    coins: Math.floor(baseRewards.coins * validation.rewardMultiplier),
    gems: Math.floor(baseRewards.gems * validation.rewardMultiplier)
  };

  // Award rewards
  user.coins += actualRewards.coins;
  user.gems += actualRewards.gems;
  completion.rewardsClaimed = true;

  res.json({
    success: true,
    rewards: actualRewards,
    totalCoins: user.coins,
    totalGems: user.gems,
    accountStatus: user.stats.flaggedForReview ? 'under_review' : 'normal'
  });
});

// Endpoint: Get user stats (for monitoring)
app.get('/api/users/:userId/stats', (req, res) => {
  const userId = req.params.userId;
  const user = users.get(userId);

  if (!user) {
    return res.status(404).json({ error: 'User not found' });
  }

  res.json({
    userId: user.id,
    coins: user.coins,
    gems: user.gems,
    completedLevels: Array.from(user.completedLevels),
    totalCompletions: user.stats.totalCompletions,
    accountStatus: user.stats.flaggedForReview ? 'under_review' : 'normal',
    suspicionScore: user.stats.suspicionScore
  });
});

// Endpoint: Get verification token (called before starting level)
app.post('/api/levels/:levelId/start', (req, res) => {
  const { userId } = req.body;
  const levelId = parseInt(req.params.levelId);

  if (!userId) {
    return res.status(400).json({ error: 'User ID required' });
  }

  initUser(userId);
  const timestamp = Date.now();
  const sessionId = crypto.randomBytes(16).toString('hex');
  const token = generateVerificationToken(userId, levelId, Math.floor(timestamp / 60000) * 60000);

  res.json({
    sessionId,
    startTime: timestamp,
    token,
    levelId
  });
});

